const raw = $input.first().json.output;

let resumeData;

try {
  const cleaned = raw.replace(/```json|```/g, "").trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  const jsonStr = (firstBrace !== -1 && lastBrace !== -1)
    ? cleaned.substring(firstBrace, lastBrace + 1)
    : cleaned;
  resumeData = JSON.parse(jsonStr);
} catch (error) {
  throw new Error("Failed to parse resume LLM JSON: " + error.message);
}

return {
  json: {
    resume_data: resumeData,
    document_id: $('Get Processing Resumes').item.json.id,
    user_id: $('Get Processing Resumes').item.json.user_id
  }
};

const raw = $input.first().json.output;
const resumeInfo = $('Parse LLM Response').item.json;

let analysis;

try {
  const cleaned = raw.replace(/```json|```/g, "").trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  const jsonStr = (firstBrace !== -1 && lastBrace !== -1)
    ? cleaned.substring(firstBrace, lastBrace + 1)
    : cleaned;
  analysis = JSON.parse(jsonStr);
} catch (error) {
  // Safe fallback
  analysis = {
    overall_score: 70,
    completeness_score: 70,
    experience_quality: 'average',
    skills_relevance: 'medium',
    red_flags: [],
    strengths: [],
    gaps: [],
    recommended_roles: [],
    status: 'needs_review'
  };
}

// Clamp score
analysis.overall_score = Math.max(0, Math.min(100, analysis.overall_score || 70));

return {
  json: {
    document_id: resumeInfo.document_id,
    user_id: resumeInfo.user_id,
    resume_data: resumeInfo.resume_data,
    analysis: analysis
  }
};

const data = $input.item.json;
const resume = data.resume_data || {};
const analysis = data.analysis || {};

// Confidence & status
const confidence_score = analysis.overall_score || 0;
let status = analysis.status || 'needs_review';
// Ensure status is a valid enum value for documents table
if (!['valid', 'needs_review', 'invalid'].includes(status)) status = 'needs_review';

return {
  json: {
    document_id: data.document_id,
    user_id: data.user_id,
    resume_data: resume,
    analysis: analysis,
    // Flattened for easy access
    candidate_name: resume.candidate_name || null,
    email: resume.email || null,
    phone: resume.phone || null,
    location: resume.location || null,
    linkedin_url: resume.linkedin_url || null,
    years_of_experience: resume.years_of_experience || 0,
    current_position: resume.current_position || null,
    current_company: resume.current_company || null,
    education_level: resume.education_level || null,
    professional_summary: resume.professional_summary || null,
    skills: resume.skills || [],
    experience: resume.experience || [],
    education: resume.education || [],
    certifications: resume.certifications || [],
    languages: resume.languages || [],
    validation: {
      confidence_score,
      status,
      completeness_score: analysis.completeness_score || 0,
      experience_quality: analysis.experience_quality || 'average',
      red_flags: analysis.red_flags || [],
      strengths: analysis.strengths || [],
      gaps: analysis.gaps || [],
      recommended_roles: analysis.recommended_roles || []
    }
  }
};

